package format

import (
	"testing"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/terraform"
)

func TestCompactDiffFormatter_Format(t *testing.T) {
	tests := []struct {
		name     string
		plan     *plans.Plan
		schemas  *terraform.Schemas
		expected string
	}{
		{
			name:     "nil plan",
			plan:     nil,
			schemas:  nil,
			expected: "",
		},
		{
			name: "plan with no changes",
			plan: &plans.Plan{
				Changes: plans.NewChangesSrc(),
			},
			schemas:  nil,
			expected: "",
		},
		{
			name: "plan with single resource creation",
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
					},
				},
			},
			schemas: nil,
			expected: "[+] aws_instance.example\n\nCreate: 1 resource\n",
		},
		{
			name: "plan with multiple resources different actions",
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_security_group",
										Name: "main",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Update,
							},
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_subnet",
										Name: "old",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Delete,
							},
						},
					},
				},
			},
			schemas: nil,
			expected: "[+] aws_instance.example\n[~] aws_security_group.main\n[-] aws_subnet.old\n\nCreate: 1 resource\nUpdate: 1 resource\nDelete: 1 resource\n",
		},
		{
			name: "plan with data source",
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.DataResourceMode,
										Type: "aws_ami",
										Name: "ubuntu",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Read,
							},
						},
					},
				},
			},
			schemas: nil,
			expected: "[<=] data.aws_ami.ubuntu\n\nRead: 1 resource\n",
		},
		{
			name: "plan filters out no-op changes",
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
							},
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "unchanged",
									},
								},
							},
							ChangeSrc: plans.ChangeSrc{
								Action: plans.NoOp,
							},
						},
					},
				},
			},
			schemas: nil,
			expected: "[+] aws_instance.example\n\nCreate: 1 resource\n",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			formatter := &CompactDiffFormatter{}
			output := formatter.Format(tt.plan, tt.schemas)
			if output != tt.expected {
				t.Errorf("Format() = %q, want %q", output, tt.expected)
			}
		})
	}
}

func TestFormatResourceAddress(t *testing.T) {
	tests := []struct {
		name     string
		addr     addrs.AbsResourceInstance
		expected string
	}{
		{
			name: "managed resource in root module",
			addr: addrs.AbsResourceInstance{
				Module: addrs.RootModuleInstance,
				Resource: addrs.ResourceInstance{
					Resource: addrs.Resource{
						Mode: addrs.ManagedResourceMode,
						Type: "aws_instance",
						Name: "example",
					},
				},
			},
			expected: "aws_instance.example",
		},
		{
			name: "data source in root module",
			addr: addrs.AbsResourceInstance{
				Module: addrs.RootModuleInstance,
				Resource: addrs.ResourceInstance{
					Resource: addrs.Resource{
						Mode: addrs.DataResourceMode,
						Type: "aws_ami",
						Name: "ubuntu",
					},
				},
			},
			expected: "data.aws_ami.ubuntu",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			output := formatResourceAddress(tt.addr)
			if output != tt.expected {
				t.Errorf("formatResourceAddress() = %q, want %q", output, tt.expected)
			}
		})
	}
}

func TestGetActionSymbol(t *testing.T) {
	tests := []struct {
		action   plans.Action
		expected string
	}{
		{plans.Create, "[+]"},
		{plans.Update, "[~]"},
		{plans.Delete, "[-]"},
		{plans.DeleteThenCreate, "[-/+]"},
		{plans.CreateThenDelete, "[+/-]"},
		{plans.Read, "[<=]"},
		{plans.Forget, "[.]"},
		{plans.CreateThenForget, "[+/.]"},
	}

	for _, tt := range tests {
		t.Run(tt.action.String(), func(t *testing.T) {
			output := getActionSymbol(tt.action)
			if output != tt.expected {
				t.Errorf("getActionSymbol(%v) = %q, want %q", tt.action, output, tt.expected)
			}
		})
	}
}

