	// Group changes by action
	actionGroups := make(map[plans.Action][]*plans.ResourceInstanceChangeSrc)
	for _, rc := range plan.Changes.Resources {
		// Only include non-NoOp changes
		if rc.Action != plans.NoOp {
			actionGroups[rc.Action] = append(actionGroups[rc.Action], rc)
		}
	}

	// Define the order to display actions
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.Delete,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.Read,
		plans.Forget,
		plans.CreateThenForget,
	}

	// Track total counts
	totalCounts := make(map[plans.Action]int)

	// Print changes grouped by action in the defined order
	for _, action := range actionOrder {
		changes := actionGroups[action]
		if len(changes) == 0 {
			continue
		}

		// Sort changes by address for consistent output
		sort.Slice(changes, func(i, j int) bool {
			return changes[i].Addr.String() < changes[j].Addr.String()
		})

		// Print each change
		for _, rc := range changes {
			resourceAddr := formatResourceAddress(rc.Addr)
			symbol := getActionSymbol(action)
			buf.WriteString(fmt.Sprintf("%s %s\n", symbol, resourceAddr))
			totalCounts[action]++
		}
	}

	// Print summary
	if len(totalCounts) > 0 {
		buf.WriteString("\n")
		for _, action := range actionOrder {
			count := totalCounts[action]
			if count > 0 {
				label := getActionLabel(action)
				plural := ""
				if count != 1 {
					plural = "s"
				}
				buf.WriteString(fmt.Sprintf("%s: %d %s%s\n", label, count, noun(action), plural))
			}
		}
	}

	return buf.String()
}

// formatResourceAddress returns a string representation of a resource instance address
// in the format "type.name" or "data.type.name" for data sources.
func formatResourceAddress(addr addrs.AbsResourceInstance) string {
	resource := addr.Resource.Resource
	module := addr.Module

	var buf bytes.Buffer

	// Include module path if not root
	if !module.IsRoot() {
		buf.WriteString(module.String())
		buf.WriteString(".")
	}

	// Add resource prefix for data sources
	if resource.Mode == addrs.DataResourceMode {
		buf.WriteString("data.")
	}

	// Add type and name
	buf.WriteString(resource.Type)
	buf.WriteString(".")
	buf.WriteString(resource.Name)

	// Add instance key if present
	if addr.InstanceKey != nil {
		buf.WriteString("[")
		buf.WriteString(addr.InstanceKey.String())
		buf.WriteString("]")
	}

	return buf.String()
}

// getActionSymbol returns a short symbol for the action.
func getActionSymbol(action plans.Action) string {
	switch action {
	case plans.Create:
		return "[+]"
	case plans.Update:
		return "[~]"
	case plans.Delete:
		return "[-]"
	case plans.DeleteThenCreate:
		return "[-/+]"
	case plans.CreateThenDelete:
		return "[+/-]"
	case plans.Read:
		return "[<=]"
	case plans.Forget:
		return "[.]"
	case plans.CreateThenForget:
		return "[+/.]"
	default:
		return "[?]"
	}
}

// getActionLabel returns a human-readable label for the action.
func getActionLabel(action plans.Action) string {
	switch action {
	case plans.Create:
		return "Create"
	case plans.Update:
		return "Update"
	case plans.Delete:
		return "Delete"
	case plans.DeleteThenCreate:
		return "Replace (delete then create)"
	case plans.CreateThenDelete:
		return "Replace (create then delete)"
	case plans.Read:
		return "Read"
	case plans.Forget:
		return "Forget"
	case plans.CreateThenForget:
		return "Create then forget"
	default:
		return "Unknown"
	}
}

// noun returns the singular noun for a resource action.
func noun(action plans.Action) string {
	switch action {
	case plans.Create, plans.Read, plans.Delete, plans.Forget:
		return "resource"
	case plans.Update, plans.DeleteThenCreate, plans.CreateThenDelete, plans.CreateThenForget:
		return "resource"
	default:
		return "resource"
	}
}

